return $input.all().map(item => ({
  json: {
    id: item.json.id, 
    email: item.json
  }
}));

const toCamelCase = (str) =>
  str
    .replace(/[-_\s]+(.)?/g, (_, c) => c ? c.toUpperCase() : '')
    .replace(/^(.)/, (m) => m.toLowerCase());

const camelCaseKeys = (obj = {}) =>
  Object.fromEntries(
    Object.entries(obj).map(([key, value]) => [
      toCamelCase(key),
      value
    ])
  );

const item = {
    id: $json.fields ? $json.fields?.MessageId : $('Wrap input').item.json.id,
    email: $json.fields ?? $('Wrap input').item.json.email,
    output: {
      jobNumber: $json.fields?.JobNumber
    }
  };

item.email.Subject = $json.fields ? $json.fields.Title : $('Wrap input').item.json.email.Subject;

return { json: item };

return {
  json: {
    id: $('Wrap email').item.json.id,
    email: $('Wrap email').item.json.email,
    job: $json.output ?? $json.job
  }
}

return $input.all().map(item => ({ 
  json: {
    job: item.json.job, 
    email: item.json.email 
  } 
}));

const toCamelCase = (str) =>
  str
    .replace(/[-_\s]+(.)?/g, (_, c) => c ? c.toUpperCase() : '')
    .replace(/^(.)/, (m) => m.toLowerCase());

const camelCaseKeys = (obj = {}) =>
  Object.fromEntries(
    Object.entries(obj).map(([key, value]) => [
      toCamelCase(key),
      value
    ])
  );

const item = {
    id: $json.fields?.MessageId,
    email: $json.fields,
    output: {
      jobNumber: $json.fields?.JobNumber
    }
  };

item.email.Subject = $json.fields.Title;

return { json: item };

const job = $json.fields;
job.JobNumber = job.Title;
job.Title = undefined;

return {
  json: {
    id: $json.fields.MessageId,
    job
  }
}

